css:
.github-ReviewsFooterView {
  margin-right: auto;
}
.github-ReviewsFooterView-footer {
  display: flex;
  align-items: center;
  padding: 10px;
  border-top: 1px solid #1d2021;
  background-color: #282828;
}
.github-ReviewsFooterView-footerTitle {
  font-size: 1.4em;
  margin: 0 20px 0 0;
}
.github-ReviewsFooterView-openReviewsButton,
.github-ReviewsFooterView-reviewChangesButton {
  margin-left: 10px;
}
.github-ReviewsFooterView-commentCount {
  margin-right: 10px;
  color: #bdae93;
}
.github-ReviewsFooterView-commentsResolved {
  color: #fbf1c7;
}
.github-ReviewsFooterView-progessBar {
  margin-right: 10px;
}
